import React, { useEffect, useState } from 'react';
import api from '../api';

const AppointmentList = () => {
  const [appointments, setAppointments] = useState<any[]>([]);
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');

  const fetchApps = () => {
    api.get('appointments/').then((res: any) => setAppointments(res.data));
  };

  useEffect(() => { fetchApps(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    await api.post('appointments/', { date, time });
    setDate(''); setTime('');
    fetchApps();
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("Cancel appointment?")) {
      await api.delete(`appointments/${id}/`);
      fetchApps();
    }
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="flex gap-2 bg-gray-50 p-4 rounded-lg">
        <input type="date" className="border p-2 rounded" value={date} onChange={e => setDate(e.target.value)} required />
        <input type="time" className="border p-2 rounded" value={time} onChange={e => setTime(e.target.value)} required />
        <button type="submit" className="bg-indigo-600 text-white px-4 py-2 rounded">Schedule</button>
      </form>
      <table className="min-w-full bg-white shadow rounded-lg">
        <thead><tr className="bg-gray-100"><th className="px-6 py-3 text-left">ID</th><th className="px-6 py-3 text-left">Schedule</th><th className="px-6 py-3 text-center">Action</th></tr></thead>
        <tbody>
          {appointments.map((a: any) => (
            <tr key={a.appointment_id} className="border-b">
              <td className="px-6 py-4">#{a.appointment_id}</td>
              <td className="px-6 py-4">{a.date} at {a.time}</td>
              <td className="px-6 py-4 text-center">
                <button onClick={() => handleDelete(a.appointment_id)} className="text-red-600">Cancel</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AppointmentList;
